import pytest
import requests

def test_delete_payroll_run_returns_400_when_mandatory_field_missing(
    hr_admin_token,
    api_base_url,
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}

    resp = requests.delete(
        f"{api_base_url}/api/payroll-runs/",
        headers=headers,
    )

    assert resp.status_code in (400, 404), (
        f"Expected 400 for missing entity_id, got {resp.status_code}: {resp.text}"
    )

import pytest
import requests

def test_delete_payroll_run_idempotency_on_already_deleted_resource(
    hr_admin_token,
    create_payroll_run,
    api_base_url,
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    entity_id = create_payroll_run(token=hr_admin_token)

    first = requests.delete(
        f"{api_base_url}/api/payroll-runs/{entity_id}", headers=headers
    )
    assert first.status_code in (200, 201), (
        f"First DELETE failed: {first.status_code}: {first.text}"
    )

    second = requests.delete(
        f"{api_base_url}/api/payroll-runs/{entity_id}", headers=headers
    )
    assert second.status_code in (404, 409), (
        f"Expected 404 or 409 on repeat delete, got {second.status_code}: {second.text}"
    )
    assert second.status_code < 500, "Server must not return 5xx on repeat delete"
